157→internal class IncompleteUtcOffset(
158→    override var isNegative: Boolean? = null,
159→    override var totalHoursAbs: Int? = null,
160→    override var minutesOfHour: Int? = null,
161→    override var secondsOfMinute: Int? = null,
162→) : UtcOffsetFieldContainer, Copyable<IncompleteUtcOffset> {
163→
164→    fun toUtcOffset(): UtcOffset {
165→        val sign = if (isNegative == true) -1 else 1
166→        return UtcOffset(
167→            totalHoursAbs?.let { it * sign }, minutesOfHour?.let { it * sign }, secondsOfMinute?.let { it * sign }
168→        )
169→    }
170→
171→    fun populateFrom(offset: UtcOffset) {
172→        isNegative = offset.totalSeconds < 0
173→        val totalSecondsAbs = offset.totalSeconds.absoluteValue
174→        totalHoursAbs = totalSecondsAbs / 3600
175→        minutesOfHour = (totalSecondsAbs / 60) % 60
176→        secondsOfMinute = totalSecondsAbs % 60
177→    }
178→
179→    override fun equals(other: Any?): Boolean =
180→        other is IncompleteUtcOffset && isNegative == other.isNegative && totalHoursAbs == other.totalHoursAbs &&
181→            minutesOfHour == other.minutesOfHour && secondsOfMinute == other.secondsOfMinute
182→
183→    override fun hashCode(): Int =
184→        isNegative.hashCode() + totalHoursAbs.hashCode() + minutesOfHour.hashCode() + secondsOfMinute.hashCode()
185→
186→    override fun copy(): IncompleteUtcOffset =
187→        IncompleteUtcOffset(isNegative, totalHoursAbs, minutesOfHour, secondsOfMinute)
188→
189→    override fun toString(): String =
190→        "${isNegative?.let { if (it) "-" else "+" } ?: " "}${totalHoursAbs ?: "??"}:${minutesOfHour ?: "??"}:${secondsOfMinute ?: "??"}"
191→}
192→
193→internal class UtcOffsetWholeHoursDirective(private val padding: Padding) :
194→    UnsignedIntFieldFormatDirective<UtcOffsetFieldContainer>(
195→        OffsetFields.totalHoursAbs,
196→        minDigits = padding.minDigits(2),
197→        spacePadding = padding.spaces(2)
198→    ) {
199→
200→    override val builderRepresentation: String
201→        get() =
202→            "${DateTimeFormatBuilder.WithUtcOffset::offsetHours.name}(${padding.toKotlinCode()})"
203→
204→    override fun equals(other: Any?): Boolean = other is UtcOffsetWholeHoursDirective && padding == other.padding
205→    override fun hashCode(): Int = padding.hashCode()
206→}
207→
208→private class UtcOffsetMinuteOfHourDirective(private val padding: Padding) :
209→    UnsignedIntFieldFormatDirective<UtcOffsetFieldContainer>(
210→        OffsetFields.minutesOfHour,
211→        minDigits = padding.minDigits(2), spacePadding = padding.spaces(2)
212→    ) {
213→
214→    override val builderRepresentation: String
215→        get() = when (padding) {
216→            Padding.NONE -> "${DateTimeFormatBuilder.WithUtcOffset::offsetMinutesOfHour.name}()"
217→            else -> "${DateTimeFormatBuilder.WithUtcOffset::offsetMinutesOfHour.name}(${padding.toKotlinCode()})"
218→        }
219→
220→    override fun equals(other: Any?): Boolean = other is UtcOffsetMinuteOfHourDirective && padding == other.padding
221→    override fun hashCode(): Int = padding.hashCode()
222→}
223→
224→private class UtcOffsetSecondOfMinuteDirective(private val padding: Padding) :
225→    UnsignedIntFieldFormatDirective<UtcOffsetFieldContainer>(
226→        OffsetFields.secondsOfMinute,
227→        minDigits = padding.minDigits(2), spacePadding = padding.spaces(2)
228→    ) {
229→
230→    override val builderRepresentation: String
231→        get() = when (padding) {
232→            Padding.NONE -> "${DateTimeFormatBuilder.WithUtcOffset::offsetSecondsOfMinute.name}()"
233→            else -> "${DateTimeFormatBuilder.WithUtcOffset::offsetSecondsOfMinute.name}(${padding.toKotlinCode()})"
234→        }
235→
236→    override fun equals(other: Any?): Boolean = other is UtcOffsetSecondOfMinuteDirective && padding == other.padding
237→    override fun hashCode(): Int = padding.hashCode()
238→}
