 6→package kotlinx.datetime.internal.format.formatter
 7→
 8→internal interface FormatterStructure<in T> {
 9→    fun format(obj: T, builder: Appendable, minusNotRequired: Boolean = false)
10→}
11→
12→internal class SpacePaddedFormatter<in T>(
13→    private val formatter: FormatterStructure<T>,
14→    private val padding: Int,
15→): FormatterStructure<T> {
16→    override fun format(obj: T, builder: Appendable, minusNotRequired: Boolean) {
17→        val string = StringBuilder().let {
18→            formatter.format(obj, it, minusNotRequired)
19→            it.toString()
20→        }
21→        repeat(padding - string.length) { builder.append(' ') }
22→        builder.append(string)
23→    }
24→}
25→
26→internal class ConditionalFormatter<in T>(
27→    private val formatters: List<Pair<T.() -> Boolean, FormatterStructure<T>>>
28→): FormatterStructure<T> {
29→    override fun format(obj: T, builder: Appendable, minusNotRequired: Boolean) {
30→        for ((condition, formatter) in formatters) {
31→            if (obj.condition()) {
32→                formatter.format(obj, builder, minusNotRequired)
33→                return
34→            }
35→        }
36→    }
37→}
38→
39→internal class SignedFormatter<in T>(
40→    private val formatter: FormatterStructure<T>,
41→    private val allSubFormatsNegative: T.() -> Boolean,
42→    private val alwaysOutputSign: Boolean,
43→): FormatterStructure<T> {
44→    override fun format(obj: T, builder: Appendable, minusNotRequired: Boolean) {
45→        val sign = if (!minusNotRequired && obj.allSubFormatsNegative()) {
46→            '-'
47→        } else if (alwaysOutputSign) {
48→            '+'
49→        } else {
50→            null
51→        }
52→        sign?.let { builder.append(it) }
53→        formatter.format(obj, builder, minusNotRequired = minusNotRequired || sign == '-')
54→    }
55→}
56→
57→internal class ConcatenatedFormatter<in T>(
58→    private val formatters: List<FormatterStructure<T>>,
59→): FormatterStructure<T> {
60→    override fun format(obj: T, builder: Appendable, minusNotRequired: Boolean) {
61→        for (formatter in formatters) {
62→            formatter.format(obj, builder, minusNotRequired)
63→        }
64→    }
65→}
