104→internal class StringFormatterStructure<in T>(
105→    private val string: (T) -> String,
106→): FormatterStructure<T> {
107→    override fun format(obj: T, builder: Appendable, minusNotRequired: Boolean) {
108→        builder.append(string(obj))
109→    }
110→}
